#include <iostream>
#include <cmath>

int countDivisors(int num, int minDivisor) {
    int count = 0;
    for (int i = minDivisor; i <= sqrt(num); i++) {
        if (num % i == 0) {
            count++;
            if (num / i != i)
                count++;
        }
    }
    return count;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        int num;
        std::cin >> num;
        std::cout << countDivisors(num, 2) << std::endl;
    }
    return 0;
},1

#include <iostream>

int gcd(int a, int b) {
    if(a == b)
        return 1;
    if(b > a)
        return 0;
    if(a % b != 0)
        return gcd(a, b + 1);
    if(a % b == 0)
        return gcd(a, b + 1) + gcd(a / b, b);
}

int main() {
    int n, i, x;
    std::cin >> n;
    for(i = 0; i < n; i++) {
        std::cin >> x;
        std::cout << gcd(x, 2) << std::endl;
    }
    return 0;
},1

#include <iostream>
#include <vector>

using namespace std;

int factorCount(int n, int i) {
    if (n == i) {
        return 1;
    }
    if (n % i != 0) {
        return factorCount(n, i + 1);
    } else {
        return 1 + factorCount(n / i, i);
    }
}

int main() {
    int times, n;
    cin >> times;
    vector<int> results(times);
    for (int i = 0; i < times; i++) {
        cin >> n;
        results[i] = factorCount(n, 2);
    }
    for (int i = 0; i < times; i++) {
        cout << results[i] << endl;
    }
    return 0;
},1

#include <iostream>

int count_divisors(int num, int div) {
    if (num < div) {
        return 0;
    }
    int count = 0;
    for (int i = div; i <= num; i++) {
        if (num % i == 0) {
            count += count_divisors(num / i, i);
        }
    }
    return count + 1;
}

int main() {
    int m;
    std::cin >> m;
    for (int j = 0; j < m; j++) {
        int n;
        std::cin >> n;
        std::cout << count_divisors(n, 2) << std::endl;
    }
    return 0;
},1

#include <iostream>
#include <cmath>

int factorize(int number) {
    int count = 0;
    while (number % 2 == 0) {
        number /= 2;
        count++;
    }
    int sqrtNum = sqrt(number);
    for (int i = 3; i <= sqrtNum; i += 2) {
        while (number % i == 0) {
            number /= i;
            count++;
        }
    }
    if (number > 2) {
        count++;
    }
    return count;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        int num;
        std::cin >> num;
        std::cout << factorize(num) << std::endl;
    }
    return 0;
},1

