int countDivisors(int num, int divisor) {
    int count = 0;
    for(int i = divisor; i <= sqrt(num); i++) {
        if(num % i == 0) {
            count++;
            count += countDivisors(num/i, i);
        }
    }
    return count;
}

int main() {
    int n;
    std::cin >> n;
    while(n--) {
        int num;
        std::cin >> num;
        std::cout << countDivisors(num, 2) << std::endl;
    }
    return 0;
