#include <cmath>
#include <iostream>

using namespace std;

int fun(int n, int begin) {
    int result = 1;
    for (int i = begin; i <= sqrt(n); i++) {
        if (n % i == 0) {
            result += fun(n / i, i);
        }
    }
    return result;
}

int main() {
    int n;
    cin >> n;
    while (n-- > 0) {
        int num;
        cin >> num;
        cout << fun(num, 2) << endl;
    }
    return 0;
},1

#include <iostream>
#include <cmath>

// Function to calculate the number of divisors
int countDivisors(int m, int min) {
    int count = 1;
    for (int i = min; i <= sqrt(m); i++) {
        if (m % i == 0) {
            count += countDivisors(m / i, i);
        }
    }
    return count;
}

// Main function
int main() {
    int n, m;
    std::cin >> n;
    while (n--) {
        std::cin >> m;
        std::cout << countDivisors(m, 2) << std::endl;
    }
    return 0;
},1

#include <iostream>
#include <vector>
#include <unordered_map>

using namespace std;

unordered_map<int, int> dp;

int fact(int n, int m) {
    if (n < m)
        return 0;
    if (n == m)
        return 1;
    if (dp.find(n) != dp.end())
        return dp[n];
    int sum = 0;
    for (int i = m; i < n; i++)
        if (n % i == 0)
            sum += fact(n / i, i);
    dp[n] = sum;
    return sum;
}

int main() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; i++)
        cin >> a[i];
    for (int i = 0; i < n; i++)
        cout << fact(a[i], 2) << endl;
    return 0;
},1

#include <iostream>
#include <cmath>

int solve(int x, int divisor = 2) {
    if (x < 2) return 0;
    if (x == 2) return 1;
    if (x % divisor != 0) return solve(x, divisor + 1);
    int count = 1;
    int quotient = x / divisor;
    if (quotient >= divisor) {
        count += solve(quotient, divisor);
    }
    return count + solve(x, divisor + 1);
}

int main() {
    int n, number;
    std::cin >> n;
    while (n--) {
        std::cin >> number;
        std::cout << solve(number) << std::endl;
    }
    return 0;
},1

#include <iostream>
#include <cmath>

int solve(int n) {
    int count = 0;
    for (int i = 2; i <= sqrt(n) + 1; i++) {
        if (n % i == 0) {
            count += solve(i) + solve(n / i);
        }
    }
    return count + 1;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        int num;
        std::cin >> num;
        std::cout << solve(num) << std::endl;
    }
    return 0;
},1

#include <iostream>
#include <cmath>

int countDivisors(int num, int div) {
    int count = 0;
    for(int i = div; i <= num; i++) {
        if(num % i == 0) {
            if(num == i) count++;
            else count += countDivisors(num / i, i);
        }
    }
    return count;
}

int main() {
    int n;
    std::cin >> n;
    while(n--) {
        int num;
        std::cin >> num;
        std::cout << countDivisors(num, 2) << std::endl;
    }
    return 0;
},1
